import{_ as t,o as a,c as r,ag as s}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Demo Accounts","description":"","frontmatter":{},"headers":[],"relativePath":"guide/demo-accounts.md","filePath":"guide/demo-accounts.md"}'),i={name:"guide/demo-accounts.md"};function n(d,e,l,o,c,m){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="demo-accounts" tabindex="-1">Demo Accounts <a class="header-anchor" href="#demo-accounts" aria-label="Permalink to &quot;Demo Accounts&quot;">​</a></h1><p>GeniusHRM ships with pre-configured demo accounts for each built-in role. After running the demo seeder (<code>php artisan db:seed --class=DemoDataSeeder</code>), the following accounts are available immediately.</p><hr><h2 id="login-credentials" tabindex="-1">Login Credentials <a class="header-anchor" href="#login-credentials" aria-label="Permalink to &quot;Login Credentials&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>Email</th><th>Password</th></tr></thead><tbody><tr><td><strong>Admin</strong></td><td>admin@geniushrm.test</td><td>Admin@1234</td></tr><tr><td><strong>HR Manager</strong></td><td>hr@geniushrm.test</td><td>Admin@1234</td></tr><tr><td><strong>Manager</strong></td><td>manager@geniushrm.test</td><td>Admin@1234</td></tr><tr><td><strong>Employee</strong></td><td>employee@geniushrm.test</td><td>Admin@1234</td></tr><tr><td><strong>Recruiter</strong></td><td>recruiter@geniushrm.test</td><td>Admin@1234</td></tr><tr><td><strong>Finance</strong></td><td>finance@geniushrm.test</td><td>Admin@1234</td></tr></tbody></table><div class="danger custom-block"><p class="custom-block-title">Change These in Production</p><p>These credentials are publicly documented. Change all default passwords immediately before going live.</p></div><hr><h2 id="role-access-summary" tabindex="-1">Role Access Summary <a class="header-anchor" href="#role-access-summary" aria-label="Permalink to &quot;Role Access Summary&quot;">​</a></h2><h3 id="admin" tabindex="-1">Admin <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;Admin&quot;">​</a></h3><p>The Admin account has unrestricted access to every part of the system.</p><ul><li>Full access to all 12 modules</li><li>Can create, edit, and delete employees, departments, and positions</li><li>Manages users, roles, and permissions</li><li>Accesses system settings (SMTP, SMS, branding, financial year)</li><li>Views audit logs</li><li>Runs payroll and approves leave</li></ul><h3 id="hr-manager" tabindex="-1">HR Manager <a class="header-anchor" href="#hr-manager" aria-label="Permalink to &quot;HR Manager&quot;">​</a></h3><p>The HR Manager handles day-to-day HR operations.</p><ul><li>Full access to the Employees module (create, edit, view)</li><li>Manages attendance records</li><li>Reviews and approves/rejects leave requests</li><li>Creates and manages performance appraisal cycles</li><li>Enrolls employees in training</li><li>Accesses all HR reports</li><li>Cannot access system settings or user management</li></ul><h3 id="manager" tabindex="-1">Manager <a class="header-anchor" href="#manager" aria-label="Permalink to &quot;Manager&quot;">​</a></h3><p>The Manager role is designed for department heads and team leads.</p><ul><li>Views employees within their department</li><li>Submits leave approvals for direct reports</li><li>Adds performance ratings for their team</li><li>Views department-level attendance and leave reports</li><li>Cannot manage payroll or system settings</li></ul><h3 id="employee" tabindex="-1">Employee <a class="header-anchor" href="#employee" aria-label="Permalink to &quot;Employee&quot;">​</a></h3><p>The Employee account represents a standard staff member.</p><ul><li>Views their own profile</li><li>Submits leave requests</li><li>Views their own attendance records and leave balances</li><li>Downloads their own payslips</li><li>Participates in performance self-assessments</li><li>Accesses available training courses and enrolls</li></ul><h3 id="recruiter" tabindex="-1">Recruiter <a class="header-anchor" href="#recruiter" aria-label="Permalink to &quot;Recruiter&quot;">​</a></h3><p>The Recruiter account manages the hiring pipeline.</p><ul><li>Creates and manages job postings</li><li>Views and processes applications</li><li>Schedules interviews</li><li>Manages candidate records</li><li>Cannot access payroll or performance modules</li></ul><h3 id="finance" tabindex="-1">Finance <a class="header-anchor" href="#finance" aria-label="Permalink to &quot;Finance&quot;">​</a></h3><p>The Finance account handles compensation and payroll.</p><ul><li>Views and manages salary structures</li><li>Runs payroll cycles</li><li>Approves payroll and generates payslips</li><li>Views payroll reports</li><li>Cannot access recruitment, performance, or training modules</li></ul><hr><h2 id="demo-data-included" tabindex="-1">Demo Data Included <a class="header-anchor" href="#demo-data-included" aria-label="Permalink to &quot;Demo Data Included&quot;">​</a></h2><p>The <code>DemoDataSeeder</code> creates:</p><table tabindex="0"><thead><tr><th>Data</th><th>Count</th></tr></thead><tbody><tr><td>Departments</td><td>8</td></tr><tr><td>Positions</td><td>20</td></tr><tr><td>Employees</td><td>50</td></tr><tr><td>Attendance records</td><td>3 months of records for all employees</td></tr><tr><td>Leave types</td><td>6 (Annual, Sick, Casual, Maternity, Paternity, Unpaid)</td></tr><tr><td>Leave requests</td><td>30 (mix of pending, approved, rejected)</td></tr><tr><td>Salary components</td><td>10</td></tr><tr><td>Salary structures</td><td>4</td></tr><tr><td>Payroll runs</td><td>3 completed runs</td></tr><tr><td>Performance cycles</td><td>2 (one active, one completed)</td></tr><tr><td>Training courses</td><td>8</td></tr><tr><td>Training sessions</td><td>12</td></tr><tr><td>Company documents</td><td>5</td></tr></tbody></table><hr><h2 id="resetting-demo-data" tabindex="-1">Resetting Demo Data <a class="header-anchor" href="#resetting-demo-data" aria-label="Permalink to &quot;Resetting Demo Data&quot;">​</a></h2><p>To reset all demo data back to the original state:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migrate:fresh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --seed</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>This command drops all tables and re-creates them. All data will be lost. Only use this command on a development or demo environment — never on production.</p></div>',35)])])}const u=t(i,[["render",n]]);export{p as __pageData,u as default};
